                  <Box>
                    <Typography variant="body2" color="text.secondary" gutterBottom>
                      排除节点（黑名单模式）
                    </Typography>
                    <TextField
                      fullWidth
                      multiline
                      rows={3}
                      placeholder="每行一个正则表达式，例如：.*过期.*"
                      value={editGroup.excludePatterns.join('\n')}
                      onChange={(e) => setEditGroup({
                        ...editGroup,
                        excludePatterns: e.target.value.split('\n').filter(p => p.trim())
                      })}
                      size="small"
                      sx={styles.textField}
                    />
                  </Box>
                </Stack>
              </Grid>
            </Grid>
          </Box>
        </DialogContent>
        <DialogActions>
          <Button 
            onClick={handleCloseGroupDialog} 
            size="small"
            sx={{
              color: 'text.secondary',
              '&:hover': {
                backgroundColor: 'action.hover',
              },
            }}
          >
            取消
          </Button>
          <Button 
            variant="contained" 
            onClick={handleSaveGroup}
            disabled={loading}
            size="small"
            sx={styles.actionButton}
          >
            保存
          </Button>
        </DialogActions>
      </Dialog>

      {/* Node Dialog */}
      <Dialog
        open={openNodeDialog}
        onClose={handleCloseNodeDialog}
        maxWidth="sm"
        fullWidth
        PaperProps={{
          sx: styles.dialog
        }}
      >
        <DialogTitle>
          {selectedNode ? '编辑节点' : '添加节点'}
        </DialogTitle>
        <DialogContent>
          <Box sx={{ pt: 2 }}>
            <Grid container spacing={2}>
              <Grid item xs={12}>
                <TextField
                  fullWidth
                  label="节点名称"
                  value={editNode.name}
                  onChange={(e) => setEditNode({ ...editNode, name: e.target.value })}
                  size="small"
                  sx={styles.textField}
                />
              </Grid>
              <Grid item xs={12}>
                <FormControl fullWidth size="small">
                  <InputLabel>节点类型</InputLabel>
                  <Select
                    value={editNode.type}
                    label="节点类型"
                    onChange={(e) => setEditNode({ ...editNode, type: e.target.value })}
                    sx={styles.textField}
                  >
                    {nodeTypes.map((type) => (
                      <MenuItem key={type.value} value={type.value}>{type.label}</MenuItem>
                    ))}
                  </Select>
                </FormControl>
              </Grid>
              <Grid item xs={12} sm={6}>
                <TextField
                  fullWidth
                  label="服务器地址"
                  value={editNode.server}
                  onChange={(e) => setEditNode({ ...editNode, server: e.target.value })}
                  size="small"
                  sx={styles.textField}
                />
              </Grid>
              <Grid item xs={12} sm={6}>
                <TextField
                  fullWidth
                  label="端口"
                  type="number"
                  value={editNode.port}
                  onChange={(e) => setEditNode({ ...editNode, port: e.target.value })}
                  size="small"
                  sx={styles.textField}
                />
              </Grid>
              {renderNodeFields()}
              <Grid item xs={12}>
                <Divider sx={{ my: 1 }}>高级设置</Divider>
              </Grid>
              <Grid item xs={12}>
                <FormControlLabel
                  control={
                    <Switch
                      checked={editNode.tls}
                      onChange={(e) => setEditNode({ ...editNode, tls: e.target.checked })}
                    />
                  }
                  label="启用 TLS"
                />
              </Grid>
              <Grid item xs={12}>
                <FormControlLabel
                  control={
                    <Switch
                      checked={editNode.udp}
                      onChange={(e) => setEditNode({ ...editNode, udp: e.target.checked })}
                    />
                  }
                  label="启用 UDP"
                />
              </Grid>
              <Grid item xs={12}>
                <FormControlLabel
                  control={
                    <Switch
                      checked={editNode.ws}
                      onChange={(e) => setEditNode({ ...editNode, ws: e.target.checked })}
                    />
                  }
                  label="WebSocket"
                />
              </Grid>
              {editNode.ws && (
                <Grid item xs={12}>
                  <TextField
                    fullWidth
                    label="WebSocket 路径"
                    value={editNode.wsPath}
                    onChange={(e) => setEditNode({ ...editNode, wsPath: e.target.value })}
                    size="small"
                    sx={styles.textField}
                  />
                </Grid>
              )}
            </Grid>
          </Box>
        </DialogContent>
        <DialogActions>
          <Button
            onClick={handleCloseNodeDialog}
            size="small"
            sx={{
              color: 'text.secondary',
              '&:hover': {
                backgroundColor: 'action.hover',
              },
            }}
          >
            取消
          </Button>
          <Button
            variant="contained"
            onClick={handleSaveNode}
            disabled={loading}
            size="small"
            sx={styles.actionButton}
          >
            保存
          </Button>
        </DialogActions>
      </Dialog>

      {/* 导入节点对话框 */}
      <Dialog
        open={importDialogOpen}
        onClose={handleCloseImportDialog}
        maxWidth="sm"
        fullWidth
        PaperProps={{
          sx: styles.dialog
        }}
      >
        <DialogTitle>导入节点</DialogTitle>
        <DialogContent>
          <Box sx={{ pt: 2 }}>
            <Grid container spacing={2}>
              <Grid item xs={12}>
                <TextField
                  fullWidth
                  multiline
                  rows={6}
                  label="节点链接"
                  value={importContent}
                  onChange={(e) => setImportContent(e.target.value)}
                  size="small"
                  placeholder="支持以下格式节点链接，每行一个：
ss://...
vmess://...
trojan://...
naive://...
hysteria://...
hysteria2://...
shadowtls://...
tun://...
redirect://...
tproxy://...
socks://...
http://..."
                  sx={styles.textField}
                />
                <FormHelperText>
                  支持 SS、VMess、Trojan、Naive、Hysteria、Hysteria2、ShadowTLS、Tun、Redirect、TProxy、Socks、HTTP 等格式节点链接，每行一个
                </FormHelperText>
              </Grid>
            </Grid>
          </Box>
        </DialogContent>
        <DialogActions>
          <Button
            onClick={handleCloseImportDialog}
            size="small"
            sx={{
              color: 'text.secondary',
              '&:hover': {
                backgroundColor: 'action.hover',
              },
            }}
          >
            取消
          </Button>
          <Button
            variant="contained"
            onClick={handleImportNodes}
            disabled={loading || !importContent}
            size="small"
            sx={styles.actionButton}
          >
            导入
          </Button>
        </DialogActions>
      </Dialog>
    </Box>
  );
};

export default Nodes;
